<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Falling Sand Sandbox</title>
    <style>
        :root {
            --bg-color: #121212;
            --text-color: #e0e0e0;
            --accent-color: #bb86fc;
            --button-bg: #333;
            --button-hover: #444;
            --canvas-border: #555;
        }

        body {
            margin: 0;
            padding: 20px;
            background-color: var(--bg-color);
            color: var(--text-color);
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            min-height: 100vh;
        }

        h1 {
            margin-bottom: 20px;
            font-weight: 300;
            letter-spacing: 1px;
        }

        .controls-container {
            display: flex;
            gap: 10px;
            margin-bottom: 20px;
            flex-wrap: wrap;
            justify-content: center;
        }

        button {
            background-color: var(--button-bg);
            color: var(--text-color);
            border: none;
            padding: 10px 20px;
            font-size: 14px;
            border-radius: 4px;
            cursor: pointer;
            transition: all 0.2s ease;
            box-shadow: 0 2px 5px rgba(0,0,0,0.3);
            min-width: 80px;
        }

        button:hover {
            background-color: var(--button-hover);
            transform: translateY(-1px);
        }

        button.active {
            background-color: var(--accent-color);
            color: #000;
            font-weight: bold;
        }

        #clear {
            background-color: #d32f2f;
            margin-left: 10px;
        }

        #clear:hover {
            background-color: #b71c1c;
        }

        .canvas-container {
            position: relative;
            border: 2px solid var(--canvas-border);
            box-shadow: 0 5px 15px rgba(0,0,0,0.5);
            cursor: crosshair;
        }

        canvas {
            display: block;
            background-color: #000;
        }
    </style>
</head>
<body>
    <h1>Falling Sand Sandbox</h1>

    <div class="controls-container">
        <button id="mat-sand" class="active">Sand</button>
        <button id="mat-water">Water</button>
        <button id="mat-wall">Wall</button>
        <button id="mat-acid">Acid</button>
        <button id="mat-empty">Eraser</button>
        <button id="clear">Clear</button>
    </div>

    <div class="canvas-container">
        <canvas id="sand" width="400" height="400"></canvas>
    </div>

    <script>
        // Configuration
        const GRID_WIDTH = 100;
        const GRID_HEIGHT = 100;
        const CELL_SIZE = 4; // Each grid cell is 4x4 pixels

        // Material constants
        const EMPTY = 0;
        const SAND = 1;
        const WATER = 2;
        const WALL = 3;
        const ACID = 4;

        // Material names mapping
        const MATERIAL_NAMES = {
            [EMPTY]: "empty",
            [SAND]: "sand",
            [WATER]: "water",
            [WALL]: "wall",
            [ACID]: "acid"
        };

        // Create grid
        let grid = new Uint8Array(GRID_WIDTH * GRID_HEIGHT).fill(EMPTY);

        // Current state
        let selectedMaterial = SAND;
        let isDrawing = false;

        // Canvas setup
        const canvas = document.getElementById('sand');
        const ctx = canvas.getContext('2d', { alpha: false });

        // Set canvas size based on grid and cell size
        canvas.width = GRID_WIDTH * CELL_SIZE;
        canvas.height = GRID_HEIGHT * CELL_SIZE;

        // Color palette
        const COLORS = {
            [EMPTY]: '#000000',
            [SAND]: '#e6c288',    // Sand color (light brown)
            [WATER]: '#4da6ff',   // Water color (blue)
            [WALL]: '#757575',    // Wall color (gray)
            [ACID]: '#adff00'     // Acid color (lime green)
        };

        // Helper functions
        function getIndex(x, y) {
            return y * GRID_WIDTH + x;
        }

        function getMaterialName(value) {
            return MATERIAL_NAMES[value] || "empty";
        }

        // Core simulation logic
        function tick() {
            // Process from bottom to top to ensure particles move at most one cell per step
            for (let y = GRID_HEIGHT - 1; y >= 0; y--) {
                // Randomize x direction for more natural movement
                const leftToRight = Math.random() > 0.5;
                const startX = leftToRight ? 0 : GRID_WIDTH - 1;
                const endX = leftToRight ? GRID_WIDTH : -1;
                const stepX = leftToRight ? 1 : -1;

                for (let x = startX; x !== endX; x += stepX) {
                    const idx = getIndex(x, y);
                    const material = grid[idx];

                    switch (material) {
                        case SAND:
                            updateSand(x, y, idx);
                            break;
                        case WATER:
                            updateWater(x, y, idx);
                            break;
                        case ACID:
                            updateAcid(x, y, idx);
                            break;
                        // WALL and EMPTY do nothing
                    }
                }
            }
        }

        function updateSand(x, y, idx) {
            if (y === GRID_HEIGHT - 1) return; // Bottom boundary

            const belowIdx = getIndex(x, y + 1);
            const belowMaterial = grid[belowIdx];

            // Try to fall straight down
            if (belowMaterial === EMPTY) {
                grid[idx] = EMPTY;
                grid[belowIdx] = SAND;
            } else if (belowMaterial === WATER || belowMaterial === ACID) {
                // Sand sinks in water/acid - swap positions
                grid[idx] = belowMaterial;
                grid[belowIdx] = SAND;
            } else if (belowMaterial === WALL || belowMaterial === SAND) {
                // Blocked, try diagonal movement
                const leftDiagX = x - 1;
                const rightDiagX = x + 1;

                let moved = false;

                // Randomize which side we check first
                if (Math.random() > 0.5) {
                    // Try left first
                    if (leftDiagX >= 0 && grid[getIndex(leftDiagX, y + 1)] === EMPTY) {
                        grid[idx] = EMPTY;
                        grid[getIndex(leftDiagX, y + 1)] = SAND;
                        moved = true;
                    } else if (rightDiagX < GRID_WIDTH && grid[getIndex(rightDiagX, y + 1)] === EMPTY) {
                        // Try right
                        grid[idx] = EMPTY;
                        grid[getIndex(rightDiagX, y + 1)] = SAND;
                        moved = true;
                    }
                } else {
                    // Try right first
                    if (rightDiagX < GRID_WIDTH && grid[getIndex(rightDiagX, y + 1)] === EMPTY) {
                        grid[idx] = EMPTY;
                        grid[getIndex(rightDiagX, y + 1)] = SAND;
                        moved = true;
                    } else if (leftDiagX >= 0 && grid[getIndex(leftDiagX, y + 1)] === EMPTY) {
                        // Try left
                        grid[idx] = EMPTY;
                        grid[getIndex(leftDiagX, y + 1)] = SAND;
                        moved = true;
                    }
                }
            }
        }

        function updateWater(x, y, idx) {
            if (y === GRID_HEIGHT - 1) return; // Bottom boundary

            const belowIdx = getIndex(x, y + 1);
            const belowMaterial = grid[belowIdx];

            // Try to fall straight down
            if (belowMaterial === EMPTY) {
                grid[idx] = EMPTY;
                grid[belowIdx] = WATER;
            } else if (belowMaterial !== WALL && belowMaterial !== SAND) {
                // Water can move through other water and acid, but not walls or sand
                // Try horizontal spreading
                const leftX = x - 1;
                const rightX = x + 1;

                let moved = false;

                // Check if we can spread horizontally
                const directions = [];
                if (leftX >= 0 && grid[getIndex(leftX, y)] === EMPTY) directions.push(leftX);
                if (rightX < GRID_WIDTH && grid[getIndex(rightX, y)] === EMPTY) directions.push(rightX);

                if (directions.length > 0) {
                    const randomDir = directions[Math.floor(Math.random() * directions.length)];
                    grid[idx] = EMPTY;
                    grid[getIndex(randomDir, y)] = WATER;
                    moved = true;
                }
            }
        }

        function updateAcid(x, y, idx) {
            if (y === GRID_HEIGHT - 1) return; // Bottom boundary

            const belowIdx = getIndex(x, y + 1);
            const belowMaterial = grid[belowIdx];

            // Try to fall straight down
            if (belowMaterial === EMPTY || belowMaterial === WATER || belowMaterial === ACID) {
                if (belowMaterial === EMPTY) {
                    grid[idx] = EMPTY;
                    grid[belowIdx] = ACID;
                } else if (belowMaterial === WATER) {
                    // Acid and water mix - random outcome
                    if (Math.random() > 0.5) {
                        grid[idx] = WATER;
                        grid[belowIdx] = ACID;
                    }
                    // Otherwise acid stays, water moves down
                } else if (belowMaterial === ACID) {
                    // Just let them pass through each other
                    grid[idx] = EMPTY;
                    grid[belowIdx] = ACID;
                }
            }

            // Acid dissolves sand and walls
            const neighbors = [
                {x: x, y: y + 1},      // below
                {x: x - 1, y: y},      // left
                {x: x + 1, y: y},      // right
                {x: x, y: y - 1}       // above (rarely happens but for completeness)
            ];

            for (const neighbor of neighbors) {
                if (neighbor.x >= 0 && neighbor.x < GRID_WIDTH && 
                    neighbor.y >= 0 && neighbor.y < GRID_HEIGHT) {

                    const nIdx = getIndex(neighbor.x, neighbor.y);
                    const nMaterial = grid[nIdx];

                    // Acid dissolves sand and walls
                    if ((nMaterial === SAND || nMaterial === WALL) && Math.random() > 0.95) {
                        grid[idx] = EMPTY;   // Acid disappears
                        grid[nIdx] = EMPTY;  // Target disappears
                        break;
                    }
                }
            }

            // Horizontal spreading for acid (similar to water)
            if (y < GRID_HEIGHT - 1 && 
                (grid[getIndex(x, y + 1)] === WATER || grid[getIndex(x, y + 1)] === ACID)) {

                const leftX = x - 1;
                const rightX = x + 1;

                // Check if we can spread horizontally
                const directions = [];
                if (leftX >= 0 && grid[getIndex(leftX, y)] === EMPTY) directions.push(leftX);
                if (rightX < GRID_WIDTH && grid[getIndex(rightX, y)] === EMPTY) directions.push(rightX);

                if (directions.length > 0) {
                    const randomDir = directions[Math.floor(Math.random() * directions.length)];
                    grid[idx] = EMPTY;
                    grid[getIndex(randomDir, y)] = ACID;
                }
            }
        }

        // Rendering
        function render() {
            ctx.fillStyle = '#000000';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            for (let y = 0; y < GRID_HEIGHT; y++) {
                for (let x = 0; x < GRID_WIDTH; x++) {
                    const idx = getIndex(x, y);
                    const material = grid[idx];

                    if (material !== EMPTY) {
                        ctx.fillStyle = COLORS[material];

                        // Add slight variation to colors for texture
                        if (material === SAND && Math.random() > 0.95) {
                            ctx.fillStyle = '#d4b177';
                        } else if (material === WATER && Math.random() > 0.95) {
                            ctx.fillStyle = '#3d96e6';
                        } else if (material === ACID && Math.random() > 0.95) {
                            ctx.fillStyle = '#a0e600';
                        }

                        // Draw cell
                        ctx.fillRect(
                            x * CELL_SIZE, 
                            y * CELL_SIZE, 
                            CELL_SIZE, 
                            CELL_SIZE
                        );
                    }
                }
            }
        }

        // Animation loop
        let lastTime = 0;
        const FPS = 60;

        function animationLoop(timestamp) {
            if (!lastTime) lastTime = timestamp;

            const elapsed = timestamp - lastTime;

            if (elapsed > 1000 / FPS) {
                tick();
                render();
                lastTime = timestamp;
            }

            requestAnimationFrame(animationLoop);
        }

        // UI Controls
        function selectMaterial(material) {
            selectedMaterial = material;

            // Update button states
            document.querySelectorAll('.controls-container button').forEach(btn => {
                btn.classList.remove('active');
            });

            const idMap = {
                [SAND]: 'mat-sand',
                [WATER]: 'mat-water',
                [WALL]: 'mat-wall',
                [ACID]: 'mat-acid',
                [EMPTY]: 'mat-empty'
            };

            if (idMap[material]) {
                document.getElementById(idMap[material]).classList.add('active');
            }
        }

        // Mouse interaction
        function handlePaint(x, y) {
            const gridX = Math.floor(x / CELL_SIZE);
            const gridY = Math.floor(y / CELL_SIZE);

            if (gridX >= 0 && gridX < GRID_WIDTH && gridY >= 0 && gridY < GRID_HEIGHT) {
                // Add some randomness to painting for natural effect
                for (let dy = -1; dy <= 1; dy++) {
                    for (let dx = -1; dx <= 1; dx++) {
                        const paintX = gridX + dx;
                        const paintY = gridY + dy;

                        if (paintX >= 0 && paintX < GRID_WIDTH && 
                            paintY >= 0 && paintY < GRID_HEIGHT &&
                            Math.random() > 0.3) {

                            const idx = getIndex(paintX, paintY);
                            grid[idx] = selectedMaterial;
                        }
                    }
                }
            }
        }

        canvas.addEventListener('mousedown', (e) => {
            isDrawing = true;
            handlePaint(e.offsetX, e.offsetY);
        });

        canvas.addEventListener('mousemove', (e) => {
            if (isDrawing) {
                handlePaint(e.offsetX, e.offsetY);
            }
        });

        window.addEventListener('mouseup', () => {
            isDrawing = false;
        });

        // Button event listeners
        document.getElementById('mat-sand').addEventListener('click', () => selectMaterial(SAND));
        document.getElementById('mat-water').addEventListener('click', () => selectMaterial(WATER));
        document.getElementById('mat-wall').addEventListener('click', () => selectMaterial(WALL));
        document.getElementById('mat-acid').addEventListener('click', () => selectMaterial(ACID));
        document.getElementById('mat-empty').addEventListener('click', () => selectMaterial(EMPTY));

        document.getElementById('clear').addEventListener('click', () => {
            grid.fill(EMPTY);
            render();
        });

        // Expose API to window
        window.sim = {
            w: GRID_WIDTH,
            h: GRID_HEIGHT,

            tick(n) {
                for (let i = 0; i < n; i++) {
                    tick();
                }
            },

            get(x, y) {
                if (x >= 0 && x < GRID_WIDTH && y >= 0 && y < GRID_HEIGHT) {
                    return getMaterialName(grid[getIndex(x, y)]);
                }
                return "empty";
            },

            set(x, y, material) {
                const materialMap = {
                    "empty": EMPTY,
                    "sand": SAND,
                    "water": WATER,
                    "wall": WALL,
                    "acid": ACID
                };

                if (material in materialMap && 
                    x >= 0 && x < GRID_WIDTH && y >= 0 && y < GRID_HEIGHT) {
                    grid[getIndex(x, y)] = materialMap[material];
                }
            },

            clear() {
                grid.fill(EMPTY);
                render();
            }
        };

        // Initialize
        selectMaterial(SAND);
        requestAnimationFrame(animationLoop);
    </script>
</body>
</html>
